#include<bits/stdc++.h>
using namespace std;
const int N=200005;
int n;
vector<int> v;
struct node
{
    int x,y;
    bool operator<(const node other)
    {
        return x<other.x;
    }
} a[N];
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i].x>>a[i].y;
    }
    sort(a+1,a+1+n);
    v.push_back(-1);
    for(int i=1;i<=n;i++)
    {
        if(a[i].y>= v[v.size()-1])
        {
            v.push_back(a[i].y);
        }
        else
        {
            int t=upper_bound(v.begin(),v.end(),a[i].y)-v.begin();
            v[t]=a[i].y;
        }
    }
    cout<<v.size()-1;
    return 0;
}
